 1	import type { FC } from 'react';
 2	import { DisplayTitle } from 'src/components/DetailItems/DetailItem';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import { ForkliftControllerModel, type K8sResourceCommon } from '@kubev2v/types';
 6	import { Text } from '@patternfly/react-core';
 7	import { MTV_SETTINGS } from '@utils/links';
 8	
 9	import { EditField } from '../cards/EditField';
10	import type { InputComponentType } from '../cards/EditFieldTypes';
11	
12	import type { EditSettingsProps } from './EditSettingsProps';
13	import { controllerCpuLimitOptions } from './options';
14	import SettingsSelectInput from './SettingsSelectInput';
15	
16	/**
17	 * ControllerCPULimitSelect component.
18	 * Wraps the SettingsSelectInput component with pre-defined options.
19	 */
20	const ControllerCPULimitSelect: InputComponentType = (props) => {
21	  return <SettingsSelectInput {...props} options={controllerCpuLimitOptions} />;
22	};
23	
24	const EditControllerCPULimit: FC<EditSettingsProps> = (props) => {
25	  const { t } = useForkliftTranslation();
26	  const { resource } = props;
27	
28	  return (
29	    <EditField
30	      {...props}
31	      resource={resource as K8sResourceCommon}
32	      jsonPath={'spec.controller_container_limits_cpu'}
33	      label={
34	        <DisplayTitle
35	          title={t('Controller main container CPU limit')}
36	          showHelpIconNextToTitle
37	          moreInfoLink={MTV_SETTINGS}
38	          helpContent={
39	            <Text>
40	              {t(
41	                'Defines the CPU limits allocated to the main container in the controller pod. The default value is 500 milliCPU.',
42	              )}
43	            </Text>
44	          }
45	          crumbs={['spec', 'controller_container_limits_cpu']}
46	        />
47	      }
48	      model={ForkliftControllerModel}
49	      helperText={t(
50	        'Enter the limit for CPU usage by the controller in milliCPU. If empty, the default value will be used.',
51	      )}
52	      InputComponent={ControllerCPULimitSelect}
53	      defaultValue="500m"
54	    />
55	  );
56	};
57	
58	export default EditControllerCPULimit;

